#include <iostream>
#include <vector>
#include <unordered_set>
using namespace std;

class Solution {
public:
    vector<int> solve(vector<vector<int>> edges) {
        // Find all nodes that have at least one child node.
        unordered_set<int> nodes_with_children;
        for (const vector<int>& edge : edges) {
            nodes_with_children.insert(edge[0]);
        }

        // Find all nodes that are missing a left child node.
        vector<int> result;
        for (int i = 1; i <= *max_element(edges[0].begin(), edges[0].end()); i++) {
            if (nodes_with_children.find(i) == nodes_with_children.end()) {
                result.push_back(i);
            }
        }
        return result;
    }
};

int main() {
    // Test case 1
    vector<vector<int>> edges1 = {{1,2},{2,3},{1,4}};
    Solution solution;
    vector<int> result1 = solution.solve(edges1);
    for (int e : result1) {
        cout << e << ' ';
    }
    cout << endl;

    return 0;
}
